solutionCode.Modal.tsx:
import { createContext, useContext, useState, type ReactNode } from 'react';

interface ModalContextValue {
  isOpen: boolean;
  open: () => void;
  close: () => void;
}

const ModalContext = createContext<ModalContextValue | null>(null);

function useModal() {
  const ctx = useContext(ModalContext);
  if (!ctx) throw new Error('useModal must be used within Modal');
  return ctx;
}

function Modal({ children }: { children: ReactNode }) {
  const [isOpen, setIsOpen] = useState(false);
  return (
    <ModalContext.Provider value={{ isOpen, open: () => setIsOpen(true), close: () => setIsOpen(false) }}>
      {children}
    </ModalContext.Provider>
  );
}

Modal.Trigger = function Trigger({ children }: { children: ReactNode }) {
  const { open } = useModal();
  return <button onClick={open}>{children}</button>;
};

Modal.Content = function Content({ children }: { children: ReactNode }) {
  const { isOpen, close } = useModal();
  if (!isOpen) return null;
  return (
    <>
      <div className="fixed inset-0 bg-black/50" onClick={close} />
      <div className="fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white rounded-lg p-6 z-50 min-w-64">
        {children}
      </div>
    </>
  );
};

Modal.Close = function Close({ children }: { children: ReactNode }) {
  const { close } = useModal();
  return <button onClick={close} className="mt-4 text-sm underline">{children}</button>;
};

export { Modal };
